package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        boolean ignoreHeaderCase = true;

        // When
        CSVFormat result = csvFormat.withIgnoreHeaderCase(ignoreHeaderCase);

        // Then
        assertEquals(ignoreHeaderCase, result.getIgnoreHeaderCase());
    }
}
